	private record CostDependencyRevision(int groupId, long logicalRevision, long physicalRevision,
			long factRevision, long winnerClearRevision) {

		private boolean current(MemoGroup group) {
			return logicalRevision == group.logicalRevision()
					&& physicalRevision == group.physicalRevision()
					&& factRevision == group.factRevision()
					&& winnerClearRevision == group.winnerClearRevision();
		}
	}

	private record CostWorkKey(CostWorkBaseKey base, long statisticsEpoch,
			List<CostDependencyRevision> dependencyRevisions,
			Map<WinnerKey, WinnerDependencyRevision> blockingWinnerRevisions) {

		private CostWorkKey {
			Objects.requireNonNull(base, "base");
			dependencyRevisions = dependencyRevisions == null || dependencyRevisions.isEmpty()
					? List.of()
					: List.copyOf(dependencyRevisions);
			blockingWinnerRevisions = blockingWinnerRevisions == null || blockingWinnerRevisions.isEmpty()
					? Map.of()
					: Map.copyOf(blockingWinnerRevisions);
		}

		private boolean currentForGroup(Memo memo, int groupId, long currentStatisticsEpoch) {
			if (statisticsEpoch != Math.max(0L, currentStatisticsEpoch)) {
				return false;
			}
			if (groupId < 0) {
				return true;
			}
			if (!blockingWinnerRevisions.isEmpty()) {
				return blockingWinnerRevisions.entrySet()
						.stream()
						.filter(entry -> entry.getKey().groupId() == groupId)
						.allMatch(entry -> entry.getValue().current(memo, entry.getKey()));
			}
			for (CostDependencyRevision revision : dependencyRevisions) {
				if (revision.groupId() == groupId && !revision.current(memo.group(groupId))) {
					return false;
				}
			}
			for (Map.Entry<WinnerKey, WinnerDependencyRevision> entry : blockingWinnerRevisions.entrySet()) {
				WinnerKey key = entry.getKey();
				if (key.groupId() == groupId && !entry.getValue().current(memo, key)) {
					return false;
				}
			}
			return true;
		}

		private boolean waitingForCurrentBlockers(Memo memo, long currentStatisticsEpoch) {
			return statisticsEpoch == Math.max(0L, currentStatisticsEpoch)
					&& !blockingWinnerRevisions.isEmpty()
					&& blockingWinnerRevisions.entrySet()
							.stream()
							.allMatch(entry -> entry.getValue().current(memo, entry.getKey()));
		}
	}

