	private record DependentPrefixPath(DependentPrefixPath parent, Winner winner, int depth,
			InputBindingContext context, DependentGoal target) {
		private DependentPrefixPath {
			if (depth < 0) {
				throw new IllegalArgumentException("depth must be non-negative");
			}
			context = context == null ? InputBindingContext.NONE : context;
			Objects.requireNonNull(target, "target");
		}

		private List<Winner> materialize(Winner terminalWinner, int inputCount) {
			ArrayList<Winner> result = new ArrayList<>(Collections.nCopies(inputCount, null));
			result.set(depth, Objects.requireNonNull(terminalWinner, "terminalWinner"));
			DependentPrefixPath current = this;
			while (current != null && current.winner() != null) {
				result.set(current.depth() - 1, current.winner());
				current = current.parent();
			}
			return List.copyOf(result);
		}
	}

